func storeToTree(store *gossip.StateStore) *merkle.Tree {
	tree := merkle.NewTree()
	entries := make(map[string][]byte)
	digest := store.Digest()
	for key := range digest.Entries {
		e, ok := store.GetEntry(key)
		if ok {
			entries[key] = encodeEntryForMerkle(e)
		}
	}
	tree.PutBatch(entries)
	return tree
}

func encodeEntryForMerkle(e *gossip.StateEntry) []byte {
	buf := make([]byte, 9+len(e.Value))
	binary.BigEndian.PutUint64(buf[:8], e.Version)
	if e.Tombstone {
		buf[8] = 1
	}
	copy(buf[9:], e.Value)
	return buf
}

